Here's a solid MSTest approach using `MockHttpMessageHandler` to control responses:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper to create a testable HttpClient
    private static (DataFetcher fetcher, MockHandler handler) CreateFetcher()
    {
        var handler = new MockHandler();
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var (fetcher, handler) = CreateFetcher();
        handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        };

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var (fetcher, handler) = CreateFetcher();
        handler.Response = new HttpResponseMessage(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        var (fetcher, handler) = CreateFetcher();
        handler.Delay = TimeSpan.FromSeconds(30); // simulate slow response
        handler.Response = new HttpResponseMessage(HttpStatusCode.OK);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // MSTest-level safety net
    public async Task FetchAsync_Throws_WhenTimeoutExpires()
    {
        var (fetcher, handler) = CreateFetcher();
        handler.Delay = TimeSpan.FromSeconds(30);
        handler.Response = new HttpResponseMessage(HttpStatusCode.OK);

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal mock handler — no external dependency needed
    private class MockHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (Delay > TimeSpan.Zero)
                await Task.Delay(Delay, cancellationToken);

            cancellationToken.ThrowIfCancellationRequested();
            return Response;
        }
    }
}
```

**Key patterns:**

- **`MockHttpMessageHandler`** — inject it into `HttpClient` to control responses without real HTTP calls
- **`CancellationTokenSource.Cancel()`** — tests immediate cancellation
- **`CancellationTokenSource(TimeSpan)`** — tests timeout-style cancellation
- **`[Timeout(5000)]`** — MSTest safety net so a broken test doesn't hang your CI indefinitely
- **`Task.Delay(delay, cancellationToken)`** in the mock — ensures the token is respected during simulated latency
